{
  "name": "DeutschMaster AI",
  "description": "An interactive German A1/A2 language learning platform featuring AI-driven lessons, mock exams, and real-time speaking practice.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ProficiencyLevel {
  A1 = 'A1',
  A2 = 'A2'
}

export type LessonStatus = 'locked' | 'available' | 'completed';

export interface Lesson {
  id: string;
  title: string;
  level: ProficiencyLevel;
  topic: string;
  description: string;
  status: LessonStatus;
  progress: number;
}

export interface QuizQuestion {
  question: string;
  options: string[];
  correctAnswer: string;
  explanation: string;
}

export interface UserProgress {
  completedLessons: string[];
  examScores: Record<string, number>;
  totalProgress: number;
  level: ProficiencyLevel;
}

export interface ExamSession {
  level: ProficiencyLevel;
  type: 'Reading' | 'Listening' | 'Writing' | 'Speaking';
  score?: number;
  feedback?: string;
}

import React from 'react';
import { ProficiencyLevel, Lesson } from './types';

export const INITIAL_LESSONS: Lesson[] = [
  { id: 'a1-1', title: 'Begrüßungen', level: ProficiencyLevel.A1, topic: 'Greetings', description: 'Learn how to say hello and introduce yourself.', status: 'available', progress: 0 },
  { id: 'a1-2', title: 'Meine Familie', level: ProficiencyLevel.A1, topic: 'Family', description: 'Describe your family members and relationships.', status: 'locked', progress: 0 },
  { id: 'a1-3', title: 'Einkaufen gehen', level: ProficiencyLevel.A1, topic: 'Shopping', description: 'Basic vocabulary for groceries and stores.', status: 'locked', progress: 0 },
  { id: 'a2-1', title: 'Vergangenheit', level: ProficiencyLevel.A2, topic: 'Past Tense', description: 'Talking about what you did yesterday (Perfekt).', status: 'locked', progress: 0 },
  { id: 'a2-2', title: 'Reisen & Urlaub', level: ProficiencyLevel.A2, topic: 'Travel', description: 'Planning trips and discussing vacations.', status: 'locked', progress: 0 },
];

export const NAV_ITEMS = [
  { label: 'Dashboard', icon: '🏠', id: 'dashboard' },
  { label: 'Lessons', icon: '📚', id: 'lessons' },
  { label: 'Practice', icon: '💬', id: 'practice' },
  { label: 'Mock Exams', icon: '📝', id: 'exams' },
  { label: 'Achievements', icon: '🏆', id: 'achievements' },
];

import { GoogleGenAI, Type } from "@google/genai";
import { ProficiencyLevel, QuizQuestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  async generateLessonContent(level: ProficiencyLevel, topic: string) {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a structured German ${level} lesson about ${topic}. Include key vocabulary (with English translations), 3 essential grammar points, and 5 example sentences. Return the response in Markdown.`,
    });
    return response.text;
  },

  async generateQuiz(level: ProficiencyLevel, topic: string): Promise<QuizQuestion[]> {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Create a 5-question multiple choice quiz for German ${level} learners on the topic: ${topic}. Each question must have exactly 4 options and 1 correct answer with a short explanation in English.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctAnswer: { type: Type.STRING },
              explanation: { type: Type.STRING }
            },
            required: ["question", "options", "correctAnswer", "explanation"]
          }
        }
      }
    });
    return JSON.parse(response.text || "[]");
  },

  async evaluateWriting(level: ProficiencyLevel, prompt: string, userText: string) {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `You are a German examiner. Evaluate this ${level} writing task. 
      Prompt: ${prompt}
      Student response: ${userText}
      Provide a score out of 100, identify mistakes, suggest corrections, and give encouraging feedback.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            score: { type: Type.NUMBER },
            mistakes: { type: Type.ARRAY, items: { type: Type.STRING } },
            corrections: { type: Type.STRING },
            feedback: { type: Type.STRING }
          },
          required: ["score", "mistakes", "corrections", "feedback"]
        }
      }
    });
    return JSON.parse(response.text || "{}");
  }
};

import React, { useState, useEffect } from 'react';
import { ProficiencyLevel, Lesson, UserProgress } from './types';
import { INITIAL_LESSONS, NAV_ITEMS } from './constants';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import LessonsView from './components/LessonsView';
import PracticeView from './components/PracticeView';
import ExamsView from './components/ExamsView';
import LessonModal from './components/LessonModal';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [userProgress, setUserProgress] = useState<UserProgress>({
    completedLessons: [],
    examScores: {},
    totalProgress: 0,
    level: ProficiencyLevel.A1
  });
  const [lessons, setLessons] = useState<Lesson[]>(INITIAL_LESSONS);
  const [selectedLesson, setSelectedLesson] = useState<Lesson | null>(null);

  // Calculate progress whenever completedLessons changes
  useEffect(() => {
    const total = lessons.length;
    const completedCount = userProgress.completedLessons.length;
    const percentage = Math.round((completedCount / total) * 100);
    setUserProgress(prev => ({ ...prev, totalProgress: percentage }));
  }, [userProgress.completedLessons, lessons.length]);

  const handleCompleteLesson = (lessonId: string) => {
    if (!userProgress.completedLessons.includes(lessonId)) {
      const nextCompleted = [...userProgress.completedLessons, lessonId];
      setUserProgress(prev => ({ ...prev, completedLessons: nextCompleted }));

      // Unlock next lesson logic
      setLessons(prev => {
        const index = prev.findIndex(l => l.id === lessonId);
        const updated = [...prev];
        updated[index] = { ...updated[index], status: 'completed', progress: 100 };
        if (updated[index + 1]) {
          updated[index + 1] = { ...updated[index + 1], status: 'available' };
        }
        return updated;
      });
    }
    setSelectedLesson(null);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard progress={userProgress} lessons={lessons} />;
      case 'lessons':
        return <LessonsView lessons={lessons} onSelectLesson={setSelectedLesson} />;
      case 'practice':
        return <PracticeView level={userProgress.level} />;
      case 'exams':
        return <ExamsView level={userProgress.level} onCompleteExam={(score) => console.log('Exam Score:', score)} />;
      case 'achievements':
        return (
          <div className="p-8 text-center">
            <h1 className="text-3xl font-bold mb-4">Your Achievements</h1>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {['Early Bird', 'Vocab Master', 'Perfect Score', 'German Native'].map(a => (
                <div key={a} className="p-6 bg-white rounded-xl shadow-sm border border-gray-100 flex flex-col items-center">
                   <span className="text-4xl mb-2">🏅</span>
                   <span className="font-semibold">{a}</span>
                </div>
              ))}
            </div>
          </div>
        );
      default:
        return <Dashboard progress={userProgress} lessons={lessons} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 overflow-y-auto">
        <header className="bg-white border-b border-gray-200 px-8 py-4 flex justify-between items-center sticky top-0 z-10">
          <div>
            <h2 className="text-xl font-bold text-slate-800">Guten Tag! 👋</h2>
            <p className="text-sm text-slate-500">Welcome back to your German journey.</p>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <div className="text-sm font-medium">Level: <span className="text-indigo-600 font-bold">{userProgress.level}</span></div>
              <div className="text-xs text-slate-400">Next goal: {userProgress.level === 'A1' ? 'A2' : 'B1'}</div>
            </div>
            <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold border-2 border-indigo-200">
              DU
            </div>
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>

      {selectedLesson && (
        <LessonModal 
          lesson={selectedLesson} 
          onClose={() => setSelectedLesson(null)} 
          onComplete={() => handleCompleteLesson(selectedLesson.id)} 
        />
      )}
    </div>
  );
};

export default App;

