export default LessonsView;

import React, { useState, useEffect } from 'react';
import { Lesson, QuizQuestion } from '../types';
import { geminiService } from '../services/geminiService';

interface LessonModalProps {
  lesson: Lesson;
  onClose: () => void;
  onComplete: () => void;
}

const LessonModal: React.FC<LessonModalProps> = ({ lesson, onClose, onComplete }) => {
  const [step, setStep] = useState<'reading' | 'quiz' | 'result'>('reading');
  const [content, setContent] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [quiz, setQuiz] = useState<QuizQuestion[]>([]);
  const [answers, setAnswers] = useState<Record<number, string>>({});
  const [quizScore, setQuizScore] = useState(0);

  useEffect(() => {
    const loadLesson = async () => {
      try {
        const text = await geminiService.generateLessonContent(lesson.level, lesson.topic);
        const quizData = await geminiService.generateQuiz(lesson.level, lesson.topic);
        setContent(text || '');
        setQuiz(quizData);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    loadLesson();
  }, [lesson]);

  const handleQuizSubmit = () => {
    let score = 0;
    quiz.forEach((q, idx) => {
      if (answers[idx] === q.correctAnswer) score++;
    });
    setQuizScore(score);
    setStep('result');
  };

  if (loading) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm">
        <div className="bg-white p-12 rounded-3xl text-center shadow-2xl max-w-sm w-full mx-4">
          <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
          <h3 className="text-2xl font-bold text-slate-800 mb-2">Preparing Lesson...</h3>
          <p className="text-slate-500">Generating customized materials for {lesson.level} level.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 p-4 md:p-12 overflow-y-auto">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-4xl max-h-full overflow-y-auto relative flex flex-col">
        <button 
          onClick={onClose}
          className="absolute top-6 right-6 text-slate-400 hover:text-slate-800 text-2xl"
        >
          ✕
        </button>

        <div className="p-8 md:p-12">
          <header className="mb-10">
            <span className="text-xs font-bold uppercase tracking-widest text-indigo-500 mb-2 block">Lesson Module</span>
            <h2 className="text-4xl font-bold text-slate-800 mb-4">{lesson.title}</h2>
            <div className="flex gap-2">
               <div className={`h-1 flex-1 rounded-full ${step === 'reading' ? 'bg-indigo-600' : 'bg-emerald-500'}`}></div>
               <div className={`h-1 flex-1 rounded-full ${step === 'quiz' ? 'bg-indigo-600' : step === 'result' ? 'bg-emerald-500' : 'bg-slate-100'}`}></div>
               <div className={`h-1 flex-1 rounded-full ${step === 'result' ? 'bg-indigo-600' : 'bg-slate-100'}`}></div>
            </div>
          </header>

          {step === 'reading' && (
            <div className="prose prose-slate max-w-none mb-12">
              <div className="whitespace-pre-wrap text-slate-700 leading-relaxed text-lg">
                {content}
              </div>
              <button 
                onClick={() => setStep('quiz')}
                className="mt-12 w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl text-xl hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all"
              >
                Take the Quiz ✍️
              </button>
            </div>
          )}

          {step === 'quiz' && (
            <div className="space-y-12">
              {quiz.map((q, idx) => (
                <div key={idx} className="bg-slate-50 p-6 rounded-2xl border border-slate-100">
                  <p className="text-xl font-bold text-slate-800 mb-6">{idx + 1}. {q.question}</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {q.options.map((opt) => (
                      <button
                        key={opt}
                        onClick={() => setAnswers({...answers, [idx]: opt})}
                        className={`p-4 rounded-xl border text-left transition-all font-medium ${
                          answers[idx] === opt 
                            ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg' 
                            : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-300'
                        }`}
                      >
                        {opt}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
              <button 
                onClick={handleQuizSubmit}
                disabled={Object.keys(answers).length < quiz.length}
                className="w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl text-xl disabled:bg-slate-300 disabled:shadow-none hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all"
              >
                Submit Answers
              </button>
            </div>
          )}

          {step === 'result' && (
            <div className="text-center py-12">
              <div className="text-8xl mb-6">{quizScore >= 4 ? '🎉' : '📚'}</div>
              <h3 className="text-4xl font-bold mb-2">Great job!</h3>
              <p className="text-2xl text-slate-500 mb-8">You scored {quizScore} out of {quiz.length}</p>

              <div className="bg-emerald-50 text-emerald-700 p-6 rounded-2xl mb-12 max-w-md mx-auto">
                <p className="font-bold mb-2">Knowledge Locked In!</p>
                <p className="text-sm">You have successfully mastered the vocabulary and grammar for this lesson.</p>
              </div>

              <button 
                onClick={onComplete}
                className="w-full max-w-sm bg-emerald-600 text-white font-bold py-4 rounded-2xl text-xl hover:bg-emerald-700 shadow-xl shadow-emerald-200 transition-all"
              >
                Continue to Dashboard
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default LessonModal;

import React, { useState } from 'react';
import { ProficiencyLevel } from '../types';
import { geminiService } from '../services/geminiService';

interface PracticeViewProps {
  level: ProficiencyLevel;
}

const PracticeView: React.FC<PracticeViewProps> = ({ level }) => {
  const [prompt] = useState('Write a short paragraph in German introducing yourself, your hobbies, and where you live.');
  const [inputText, setInputText] = useState('');
  const [feedback, setFeedback] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async () => {
    setLoading(true);
    try {
      const result = await geminiService.evaluateWriting(level, prompt, inputText);
      setFeedback(result);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-8">
      <h1 className="text-3xl font-bold mb-8">Writing Lab</h1>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div className="bg-indigo-50 border-l-4 border-indigo-500 p-6 rounded-r-xl">
            <h4 className="font-bold text-indigo-900 mb-2">Prompt:</h4>
            <p className="text-indigo-800 text-lg">{prompt}</p>
          </div>

          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <textarea
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder="Schreiben Sie hier..."
              className="w-full h-64 p-6 outline-none text-lg resize-none"
            ></textarea>
            <div className="bg-slate-50 px-6 py-4 flex justify-between items-center border-t border-slate-200">
              <span className="text-xs text-slate-400 font-medium">
                {inputText.split(/\s+/).filter(Boolean).length} words
              </span>
              <button
                onClick={handleSubmit}
                disabled={loading || inputText.length < 10}
                className="bg-indigo-600 text-white font-bold py-2 px-8 rounded-lg disabled:bg-slate-300 hover:bg-indigo-700 transition-colors"
              >
                {loading ? 'Analyzing...' : 'Submit to AI Examiner'}
              </button>
            </div>
          </div>
        </div>

        <div>
          {feedback ? (
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-8 space-y-6 animate-in slide-in-from-right duration-500">
              <div className="flex justify-between items-center">
                <h3 className="text-2xl font-bold">Feedback</h3>
                <div className="bg-indigo-100 text-indigo-700 w-16 h-16 rounded-full flex items-center justify-center text-2xl font-black border-4 border-white shadow-lg">
                  {feedback.score}
                </div>
              </div>

              <div>
                <h4 className="font-bold text-rose-600 mb-2 uppercase text-xs tracking-widest">Mistakes Identified</h4>
                <ul className="space-y-2">
                  {feedback.mistakes?.map((m: string, i: number) => (
                    <li key={i} className="bg-rose-50 text-rose-800 p-3 rounded-lg text-sm flex gap-2">
                      <span>•</span> {m}
                    </li>
                  ))}
                </ul>
              </div>

              <div className="bg-emerald-50 p-4 rounded-xl">
                <h4 className="font-bold text-emerald-800 mb-2 uppercase text-xs tracking-widest">Corrected Version</h4>
                <p className="text-emerald-900 italic leading-relaxed">{feedback.corrections}</p>
              </div>

              <div className="pt-4 border-t border-slate-100">
                 <p className="text-slate-600 leading-relaxed italic">"{feedback.feedback}"</p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center bg-slate-100/50 rounded-2xl border-2 border-dashed border-slate-200 text-center p-8">
              <div className="text-6xl mb-4">🕵️‍♂️</div>
