import React, { useState, useEffect } from 'react';
import { Lesson, QuizQuestion } from '../types';
import { geminiService } from '../services/geminiService';
import Assistant from './Assistant';

interface LessonModalProps {
  lesson: Lesson;
  onClose: () => void;
  onComplete: () => void;
}

const LessonModal: React.FC<LessonModalProps> = ({ lesson, onClose, onComplete }) => {
  const [step, setStep] = useState<'reading' | 'quiz' | 'result'>('reading');
  const [content, setContent] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [quiz, setQuiz] = useState<QuizQuestion[]>([]);
  const [answers, setAnswers] = useState<Record<number, string>>({});
  const [quizScore, setQuizScore] = useState(0);
  const [assistantMessage, setAssistantMessage] = useState('Hallo! Ready to learn?');

  useEffect(() => {
    const loadLesson = async () => {
      try {
        const text = await geminiService.generateLessonContent(lesson.level, lesson.topic);
        const quizData = await geminiService.generateQuiz(lesson.level, lesson.topic);
        setContent(text || '');
        setQuiz(quizData);
        setAssistantMessage(`Willkommen! In this lesson on ${lesson.topic}, we will focus on essential ${lesson.level} structures. Viel Erfolg!`);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    loadLesson();
  }, [lesson]);

  const handleQuizSubmit = () => {
    let score = 0;
    quiz.forEach((q, idx) => {
      if (answers[idx] === q.correctAnswer) score++;
    });
    setQuizScore(score);
    setStep('result');
    if (score === quiz.length) {
      setAssistantMessage("Ausgezeichnet! You've mastered this topic perfectly!");
    } else if (score >= 3) {
      setAssistantMessage("Gut gemacht! Almost perfect, keep practicing those tricky parts.");
    } else {
      setAssistantMessage("Don't worry! German grammar can be hard. Let's try again later.");
    }
  };

  if (loading) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm">
        <div className="bg-white p-12 rounded-3xl text-center shadow-2xl max-w-sm w-full mx-4">
          <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
          <h3 className="text-2xl font-bold text-slate-800 mb-2">Preparing Lesson...</h3>
          <p className="text-slate-500">Our Octo-Assistant is gathering the best materials for you.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 p-4 md:p-8 overflow-y-auto">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-6xl max-h-full overflow-hidden relative flex flex-col md:flex-row">
        {/* Assistant Side Panel */}
        <div className="hidden md:flex w-72 bg-slate-50 border-r border-slate-100 items-center justify-center p-6 shrink-0">
           <Assistant message={assistantMessage} isTalking={loading === false} />
        </div>

        <div className="flex-1 overflow-y-auto relative p-8 md:p-12">
          <button 
            onClick={onClose}
            className="absolute top-6 right-6 text-slate-400 hover:text-slate-800 text-2xl z-10"
          >
            ✕
          </button>

          <header className="mb-10">
            <span className="text-xs font-bold uppercase tracking-widest text-indigo-500 mb-2 block">Lesson Module</span>
            <h2 className="text-4xl font-bold text-slate-800 mb-4">{lesson.title}</h2>

            {/* Mobile Assistant view */}
            <div className="md:hidden flex items-center gap-4 bg-slate-50 p-4 rounded-2xl mb-6">
               <div className="w-16 h-16"><Assistant message={assistantMessage} isTalking={true} /></div>
               <p className="text-xs italic text-slate-600">{assistantMessage}</p>
            </div>

            <div className="flex gap-2">
               <div className={`h-1 flex-1 rounded-full ${step === 'reading' ? 'bg-indigo-600' : 'bg-emerald-500'}`}></div>
               <div className={`h-1 flex-1 rounded-full ${step === 'quiz' ? 'bg-indigo-600' : step === 'result' ? 'bg-emerald-500' : 'bg-slate-100'}`}></div>
               <div className={`h-1 flex-1 rounded-full ${step === 'result' ? 'bg-indigo-600' : 'bg-slate-100'}`}></div>
            </div>
          </header>

          {step === 'reading' && (
            <div className="prose prose-slate max-w-none mb-12">
              <div className="whitespace-pre-wrap text-slate-700 leading-relaxed text-lg lesson-content">
                {content.split(' ').map((word, i) => {
                  // Highlighting logic for the main content
                  const isGermanKey = /^[A-Z][a-zäöüß]+/.test(word); // Simple heuristic for German Nouns
                  return (
                    <span key={i} className={isGermanKey ? 'text-indigo-600 font-bold' : ''}>
                      {word}{' '}
                    </span>
                  );
                })}
              </div>
              <button 
                onClick={() => {
                  setStep('quiz');
                  setAssistantMessage("Now let's test what you've learned. You can do this! 📝");
                }}
                className="mt-12 w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl text-xl hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all"
              >
                Take the Quiz ✍️
              </button>
            </div>
          )}

          {step === 'quiz' && (
            <div className="space-y-12">
              {quiz.map((q, idx) => (
                <div key={idx} className="bg-slate-50 p-6 rounded-2xl border border-slate-100">
                  <p className="text-xl font-bold text-slate-800 mb-6">{idx + 1}. {q.question}</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {q.options.map((opt) => (
                      <button
                        key={opt}
                        onClick={() => setAnswers({...answers, [idx]: opt})}
                        className={`p-4 rounded-xl border text-left transition-all font-medium ${
                          answers[idx] === opt 
                            ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg' 
                            : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-300'
                        }`}
                      >
                        {opt}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
              <button 
                onClick={handleQuizSubmit}
                disabled={Object.keys(answers).length < quiz.length}
                className="w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl text-xl disabled:bg-slate-300 disabled:shadow-none hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all"
              >
                Submit Answers
              </button>
            </div>
          )}

          {step === 'result' && (
            <div className="text-center py-12">
              <div className="text-8xl mb-6">{quizScore >= 4 ? '🎉' : '📚'}</div>
              <h3 className="text-4xl font-bold mb-2">{quizScore >= 4 ? 'Bravo!' : 'Keep going!'}</h3>
              <p className="text-2xl text-slate-500 mb-8">You scored {quizScore} out of {quiz.length}</p>

              <div className="bg-emerald-50 text-emerald-700 p-6 rounded-2xl mb-12 max-w-md mx-auto">
                <p className="font-bold mb-2">Knowledge Locked In!</p>
                <p className="text-sm">This lesson is now part of your language toolkit.</p>
              </div>

              <button 
                onClick={onComplete}
                className="w-full max-w-sm bg-emerald-600 text-white font-bold py-4 rounded-2xl text-xl hover:bg-emerald-700 shadow-xl shadow-emerald-200 transition-all"
              >
                Continue to Dashboard
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default LessonModal;

import React, { useState, useEffect, useRef } from 'react';

interface AssistantProps {
  message: string;
  isTalking?: boolean;
  mood?: 'happy' | 'thinking' | 'neutral' | 'excited';
}

const Assistant: React.FC<AssistantProps> = ({ message, isTalking = false, mood = 'neutral' }) => {
  const [displayText, setDisplayText] = useState('');
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  // Eye tracking logic
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (containerRef.current) {
        const rect = containerRef.current.getBoundingClientRect();
        const centerX = rect.left + rect.width / 2;
        const centerY = rect.top + rect.height / 2;
        const angle = Math.atan2(e.clientY - centerY, e.clientX - centerX);
        const distance = Math.min(6, Math.hypot(e.clientX - centerX, e.clientY - centerY) / 20);
        setMousePos({
          x: Math.cos(angle) * distance,
          y: Math.sin(angle) * distance,
        });
      }
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  // Typing effect with randomized color triggers
  useEffect(() => {
    let i = 0;
    setDisplayText('');
    const interval = setInterval(() => {
      if (i < message.length) {
        setDisplayText((prev) => prev + message.charAt(i));
        i++;
      } else {
        clearInterval(interval);
      }
    }, 25);
    return () => clearInterval(interval);
  }, [message]);

  return (
    <div ref={containerRef} className="flex flex-col items-center gap-8 p-4 perspective-1000">
      {/* Dynamic Speech Bubble */}
      <div className="relative group">
        <div className="absolute -inset-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 rounded-2xl blur opacity-20 group-hover:opacity-40 transition duration-1000 group-hover:duration-200"></div>
        <div className="relative bg-white/90 backdrop-blur-md p-5 rounded-2xl shadow-2xl border border-white/50 max-w-[220px] transform transition-all duration-300 hover:scale-105">
          <p className="text-sm font-medium text-slate-800 leading-relaxed font-sans italic">
            {displayText.split(' ').map((word, idx) => {
              const highlights = ['text-indigo-600', 'text-amber-500', 'text-emerald-500', 'text-rose-500', 'text-purple-600'];
              const isGerman = /^[A-Z]/.test(word) && word.length > 3;
              return (
                <span 
                  key={idx} 
                  className={`${isGerman ? highlights[idx % highlights.length] + ' font-bold drop-shadow-sm animate-pulse' : ''} inline-block transition-colors`}
                >
                  {word}{' '}
                </span>
              );
            })}
          </p>
          {/* Bubble tail */}
          <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-white/90 border-b border-r border-white/50 rotate-45"></div>
        </div>
      </div>

      {/* The 3D Crystal Octahedron */}
      <div className="relative w-28 h-28 preserve-3d">
        {/* Floating "Hands" - now glowing orbs */}
        <div className="absolute -left-10 top-1/2 w-3 h-3 bg-indigo-400 rounded-full blur-[2px] shadow-[0_0_15px_rgba(129,140,248,0.8)] animate-hand-left"></div>
        <div className="absolute -right-10 top-1/2 w-3 h-3 bg-indigo-400 rounded-full blur-[2px] shadow-[0_0_15px_rgba(129,140,248,0.8)] animate-hand-right"></div>

        {/* Main Body */}
        <div className={`
          relative w-full h-full preserve-3d animate-float
          transition-all duration-700
          ${mood === 'excited' ? 'scale-125' : ''}
          ${mood === 'thinking' ? 'rotate-y-180' : ''}
        `}>
          {/* Octahedron Faces using CSS 3D */}
          <div className="absolute inset-0 preserve-3d flex items-center justify-center">
            {/* Front Top */}
            <div className="absolute w-0 h-0 border-l-[50px] border-l-transparent border-r-[50px] border-r-transparent border-bottom-[80px] border-bottom-indigo-500/80 rotate-x-35 translate-z-20 backdrop-blur-sm"></div>
            {/* Front Bottom */}
            <div className="absolute w-0 h-0 border-l-[50px] border-l-transparent border-r-[50px] border-r-transparent border-top-[80px] border-top-indigo-600/90 -rotate-x-35 -translate-z-20"></div>

            {/* Stylized Body Container for the Face */}
            <div className="absolute inset-2 bg-gradient-to-br from-indigo-400 to-indigo-700 rounded-full shadow-[inset_0_0_20px_rgba(255,255,255,0.4)] flex items-center justify-center overflow-hidden border-2 border-indigo-300/30">
               {/* Animated Internal Core */}
               <div className="absolute w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-white/30 via-transparent to-transparent animate-pulse"></div>

               {/* Face Controls */}
               <div className={`relative flex flex-col items-center transition-transform duration-300 ${isTalking ? 'translate-y-[-2px]' : ''}`}>
                  {/* The Eye */}
                  <div className="relative w-10 h-10 bg-white rounded-full flex items-center justify-center border-[3px] border-slate-900 shadow-inner group-hover:scale-110 transition-transform">
                    <div 
                      className="w-4 h-4 bg-slate-900 rounded-full flex items-center justify-center transition-transform duration-75"
                      style={{ transform: `translate(${mousePos.x}px, ${mousePos.y}px)` }}
                    >
                      <div className="w-1.5 h-1.5 bg-white rounded-full translate-x-1 translate-y-[-1px]"></div>
                    </div>
                    {/* Blinking layer */}
