        .rotate-x-35 { transform: rotateX(35deg); }
        .rotate-y-180 { transform: rotateY(180deg); }
        .translate-z-20 { transform: translateZ(20px); }

        @keyframes float {
          0%, 100% { transform: translateY(0) rotateX(5deg) rotateY(-5deg); }
          50% { transform: translateY(-20px) rotateX(-5deg) rotateY(10deg); }
        }

        @keyframes blink {
          0%, 90%, 100% { transform: scaleY(0); }
          95% { transform: scaleY(1); }
        }

        @keyframes hand-left {
          0%, 100% { transform: translate(0, 0) scale(1); }
          50% { transform: translate(-10px, -20px) scale(1.2); }
        }

        @keyframes hand-right {
          0%, 100% { transform: translate(0, 0) scale(1); }
          50% { transform: translate(10px, -20px) scale(1.2); }
        }

        .animate-float { animation: float 6s ease-in-out infinite; }
        .animate-blink { animation: blink 4s linear infinite; }
        .animate-hand-left { animation: hand-left 3s ease-in-out infinite; }
        .animate-hand-right { animation: hand-right 3s ease-in-out infinite 0.5s; }
      `}} />
    </div>
  );
};

