                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {q.options.map((opt) => (
                        <button
                          key={opt}
                          onClick={() => {
                            setAnswers({...answers, [idx]: opt});
                            setAssistantMood('happy');
                          }}
                          className={`group p-5 rounded-2xl border-2 text-left transition-all relative overflow-hidden ${
                            answers[idx] === opt 
                              ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-[1.02]' 
                              : 'bg-slate-50 border-slate-100 text-slate-600 hover:border-indigo-200 hover:bg-white'
                          }`}
                        >
                          <span className="relative z-10 font-bold">{opt}</span>
                          {answers[idx] === opt && (
                            <div className="absolute top-0 right-0 p-2">
                               <div className="w-6 h-6 bg-white/20 rounded-full flex items-center justify-center text-xs">✓</div>
                            </div>
                          )}
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
                <button 
                  onClick={handleQuizSubmit}
                  disabled={Object.keys(answers).length < quiz.length}
                  className="w-full bg-indigo-600 text-white font-black py-6 rounded-3xl text-2xl disabled:bg-slate-200 disabled:text-slate-400 hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all transform hover:-translate-y-1 active:translate-y-0"
                >
                  Finalize and Check Result
