                <h3 className="text-5xl font-display font-bold mb-4 bg-gradient-to-r from-indigo-600 to-purple-600 bg-clip-text text-transparent">
                  {quizScore >= 4 ? 'Wunderbar!' : 'Keep Pushing!'}
                </h3>
                <p className="text-3xl text-slate-400 mb-12">
                  Result: <span className="text-slate-800 font-black">{quizScore} / {quiz.length}</span>
                </p>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-2xl mx-auto mb-12">
                   <div className="bg-emerald-50 border border-emerald-100 p-8 rounded-3xl text-left">
                      <p className="text-emerald-700 font-black text-xl mb-2">Knowledge Gained</p>
                      <p className="text-emerald-600">You successfully acquired {lesson.topic} vocabulary and A1 structures.</p>
                   </div>
                   <div className="bg-indigo-50 border border-indigo-100 p-8 rounded-3xl text-left">
                      <p className="text-indigo-700 font-black text-xl mb-2">Next Step</p>
                      <p className="text-indigo-600">Apply these words in the Writing Lab for extra XP!</p>
                   </div>
                </div>

                <button 
                  onClick={onComplete}
                  className="w-full max-w-md bg-slate-900 text-white font-black py-6 rounded-3xl text-2xl hover:bg-black shadow-2xl transition-all transform hover:scale-105 active:scale-95"
                >
                  Complete Mission
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

