import React, { useState, useEffect, useRef } from 'react';

interface AssistantProps {
  message: string;
  isTalking?: boolean;
  mood?: 'happy' | 'thinking' | 'neutral' | 'excited';
}

const Assistant: React.FC<AssistantProps> = ({ message, isTalking = false, mood = 'neutral' }) => {
  const [displayText, setDisplayText] = useState('');
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (containerRef.current) {
        const rect = containerRef.current.getBoundingClientRect();
        const centerX = rect.left + rect.width / 2;
        const centerY = rect.top + rect.height / 2;
        const angle = Math.atan2(e.clientY - centerY, e.clientX - centerX);
        const distance = Math.min(5, Math.hypot(e.clientX - centerX, e.clientY - centerY) / 25);
        setMousePos({
          x: Math.cos(angle) * distance,
          y: Math.sin(angle) * distance,
        });
      }
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  useEffect(() => {
    let i = 0;
    setDisplayText('');
    const interval = setInterval(() => {
      if (i < message.length) {
        setDisplayText((prev) => prev + message.charAt(i));
        i++;
      } else {
        clearInterval(interval);
      }
    }, 20);
    return () => clearInterval(interval);
  }, [message]);

  const Eye = () => (
    <div className="relative w-8 h-8 bg-white rounded-full flex items-center justify-center border-[2px] border-slate-900 shadow-inner overflow-hidden">
      <div 
        className="w-3.5 h-3.5 bg-slate-900 rounded-full flex items-center justify-center transition-transform duration-75"
        style={{ transform: `translate(${mousePos.x}px, ${mousePos.y}px)` }}
      >
        <div className="w-1 h-1 bg-white rounded-full translate-x-0.5 translate-y-[-0.5px]"></div>
      </div>
      <div className="absolute inset-0 bg-indigo-500 origin-top scale-y-0 animate-blink"></div>
    </div>
  );

  return (
    <div ref={containerRef} className="flex flex-col items-center gap-6 p-4 perspective-1000">
      <div className="relative group">
        <div className="absolute -inset-1 bg-indigo-400 rounded-2xl blur opacity-10 group-hover:opacity-30 transition duration-1000"></div>
        <div className="relative bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-xl border border-indigo-100/50 max-w-[200px] transform hover:rotate-1 transition-all">
          <p className="text-sm font-marker text-indigo-900 leading-tight">
            {displayText}
          </p>
          <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-white/95 border-b border-r border-indigo-100/50 rotate-45"></div>
        </div>
      </div>

      <div className="relative w-28 h-28 preserve-3d animate-float">
        {/* Glow Orbs */}
        <div className="absolute -left-12 top-1/2 w-2 h-2 bg-amber-400 rounded-full blur-[1px] animate-pulse"></div>
        <div className="absolute -right-12 top-1/2 w-2 h-2 bg-emerald-400 rounded-full blur-[1px] animate-pulse delay-500"></div>

        <div className={`w-full h-full preserve-3d flex items-center justify-center transition-transform duration-500 ${mood === 'thinking' ? 'rotate-y-12' : ''}`}>
           <div className="absolute inset-0 bg-gradient-to-tr from-indigo-600 via-indigo-500 to-indigo-400 clip-octahedron shadow-2xl">
              <div className="absolute inset-0 flex flex-col items-center justify-center gap-2">
                 <div className="flex gap-2">
                    <Eye />
                    <Eye />
                 </div>
                 <div className={`
                    w-4 h-1 bg-slate-900 rounded-full transition-all duration-200
                    ${isTalking ? 'h-3 w-3 rounded-full' : ''}
                    ${mood === 'happy' ? 'w-6 h-2 rounded-b-full rounded-t-none' : ''}
                 `}></div>
              </div>
              <div className="absolute top-0 right-0 w-1/2 h-1/2 bg-white/10"></div>
           </div>
        </div>
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        .perspective-1000 { perspective: 1000px; }
        .preserve-3d { transform-style: preserve-3d; }
        .clip-octahedron { clip-path: polygon(50% 0%, 100% 50%, 50% 100%, 0% 50%); }
        @keyframes float {
          0%, 100% { transform: translateY(0) rotateZ(-2deg); }
          50% { transform: translateY(-12px) rotateZ(2deg); }
        }
        @keyframes blink {
          0%, 94%, 100% { transform: scaleY(0); }
          97% { transform: scaleY(1); }
        }
        .animate-float { animation: float 5s ease-in-out infinite; }
        .animate-blink { animation: blink 4s linear infinite; }
      `}} />
    </div>
  );
};

export default Assistant;

import React, { useState, useEffect } from 'react';
import { Lesson, QuizQuestion } from '../types';
import { geminiService } from '../services/geminiService';
import Assistant from './Assistant';

interface LessonModalProps {
  lesson: Lesson;
  onClose: () => void;
  onComplete: () => void;
}

const LessonModal: React.FC<LessonModalProps> = ({ lesson, onClose, onComplete }) => {
  const [step, setStep] = useState<'reading' | 'quiz' | 'result'>('reading');
  const [content, setContent] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [quiz, setQuiz] = useState<QuizQuestion[]>([]);
  const [answers, setAnswers] = useState<Record<number, string>>({});
  const [quizScore, setQuizScore] = useState(0);
  const [assistantMessage, setAssistantMessage] = useState('Hallo! Bereit?');
  const [assistantMood, setAssistantMood] = useState<'neutral' | 'happy' | 'thinking' | 'excited'>('neutral');

  useEffect(() => {
    const loadLesson = async () => {
      setAssistantMood('thinking');
      try {
        const text = await geminiService.generateLessonContent(lesson.level, lesson.topic);
        const quizData = await geminiService.generateQuiz(lesson.level, lesson.topic);
        setContent(text || '');
        setQuiz(quizData);
        setAssistantMessage(`Super! Today we dive into ${lesson.topic}. Let's take some notes!`);
        setAssistantMood('happy');
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    loadLesson();
  }, [lesson]);

  const handleQuizSubmit = () => {
    let score = 0;
    quiz.forEach((q, idx) => {
      if (answers[idx] === q.correctAnswer) score++;
    });
    setQuizScore(score);
    setStep('result');
    if (score === quiz.length) {
      setAssistantMessage("Perfekt! All correct. You're a German star! ⭐");
      setAssistantMood('excited');
    } else {
      setAssistantMessage("Well done! Reviewing notes is the key to success. ✍️");
      setAssistantMood('happy');
    }
  };

  const Notepad = ({ text }: { text: string }) => {
    return (
      <div className="relative bg-[#fdfdfd] shadow-2xl p-10 md:p-16 border border-slate-200 rounded-sm rotate-1 transform-gpu hover:rotate-0 transition-transform duration-500 overflow-hidden">
        {/* Margin Line */}
        <div className="absolute left-12 md:left-20 top-0 bottom-0 w-[2px] bg-rose-200 opacity-60"></div>

        {/* Paper Lines */}
        <div className="absolute inset-0 pointer-events-none" style={{
          backgroundImage: 'linear-gradient(#e5effb 1px, transparent 1px)',
          backgroundSize: '100% 2.2rem',
          marginTop: '0.5rem'
        }}></div>

        {/* Content */}
        <div className="relative z-10 font-handwritten text-xl leading-[2.2rem] text-slate-800">
           {text.split('\n').map((line, lineIdx) => (
             <p key={lineIdx} className="mb-4">
                {line.split(' ').map((word, wordIdx) => {
                  const isNoun = /^[A-Z]/.test(word) && word.length > 3;
                  const isImportant = word.includes('!') || word.length > 8;

                  if (isNoun) {
                    return (
                      <span key={wordIdx} className="inline-block relative px-1 mx-0.5 group">
                        <span className="relative z-10 text-indigo-700 font-bold">{word} </span>
                        <svg className="absolute -bottom-1 left-0 w-full h-2 text-rose-400/40 opacity-100" viewBox="0 0 100 10" preserveAspectRatio="none">
                          <path d="M0,5 Q25,0 50,5 T100,5" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" />
                        </svg>
                      </span>
                    );
                  }

                  if (isImportant) {
                    return (
                      <span key={wordIdx} className="inline-block relative px-1 mx-0.5">
                        <span className="relative z-10">{word} </span>
                        <span className="absolute inset-0 bg-emerald-100/60 -skew-x-12 -rotate-1 rounded-sm scale-110"></span>
                      </span>
                    );
                  }

                  return <span key={wordIdx}>{word} </span>;
                })}
             </p>
           ))}
        </div>

        {/* Doodles */}
        <div className="absolute top-10 right-10 opacity-20 text-indigo-600 select-none pointer-events-none">
           <svg className="w-16 h-16" viewBox="0 0 100 100">
              <path d="M50,10 L60,40 L90,40 L65,60 L75,90 L50,70 L25,90 L35,60 L10,40 L40,40 Z" fill="none" stroke="currentColor" strokeWidth="2" />
           </svg>
        </div>
        <div className="absolute bottom-10 left-4 opacity-10 text-emerald-600 font-marker rotate-12">XP+</div>
      </div>
    );
  };

  if (loading) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-indigo-50/80 backdrop-blur-sm">
        <div className="text-center">
           <div className="w-20 h-20 mb-8 mx-auto"><Assistant message="..." mood="thinking" /></div>
           <h3 className="text-2xl font-marker text-indigo-900 animate-pulse">Lektion wird vorbereitet...</h3>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 p-4 md:p-12 overflow-y-auto">
      <div className="bg-[#f8f9fc] rounded-[40px] shadow-3xl w-full max-w-7xl max-h-full overflow-hidden relative flex flex-col md:flex-row border-8 border-white">

        {/* Assistant Panel */}
        <div className="hidden md:flex w-72 bg-indigo-50 border-r border-indigo-100 items-center justify-center p-6 shrink-0">
           <Assistant message={assistantMessage} mood={assistantMood} />
        </div>

        <div className="flex-1 overflow-y-auto p-6 md:p-16 relative bg-[radial-gradient(#e5e7eb_1px,transparent_1px)] [background-size:20px_20px]">
          <button 
            onClick={onClose}
            className="absolute top-8 right-8 w-12 h-12 flex items-center justify-center bg-white rounded-full shadow-lg hover:bg-rose-50 hover:text-rose-500 transition-all z-50 font-bold"
          >
            ✕
          </button>

          <div className="max-w-4xl mx-auto">
            <header className="mb-12">
              <div className="flex items-center gap-4 mb-4">
                 <div className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-marker text-lg shadow-lg shadow-indigo-200">
                   Level: {lesson.level}
                 </div>
                 <h2 className="text-4xl font-display font-black text-slate-800">{lesson.title}</h2>
              </div>
              <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden flex">
                 <div className={`h-full transition-all duration-700 ${step === 'reading' ? 'w-1/3 bg-indigo-500' : step === 'quiz' ? 'w-2/3 bg-amber-500' : 'w-full bg-emerald-500'}`}></div>
              </div>
            </header>

            {step === 'reading' && (
              <div className="animate-in slide-in-from-bottom-8 duration-500">
                <Notepad text={content} />
                <button 
                  onClick={() => {
                    setStep('quiz');
                    setAssistantMessage("Ready for the checkup? You got this! 📝");
                  }}
                  className="mt-12 w-full bg-indigo-600 text-white font-black py-6 rounded-3xl text-2xl hover:bg-indigo-700 shadow-2xl hover:scale-[1.02] transition-all"
                >
                  Start Quiz Challenge →
                </button>
              </div>
            )}

            {step === 'quiz' && (
              <div className="space-y-8 animate-in fade-in duration-500">
                {quiz.map((q, idx) => (
                  <div key={idx} className="bg-white p-10 rounded-[32px] border-4 border-slate-50 shadow-sm">
                    <p className="text-2xl font-bold text-slate-800 mb-8 flex gap-4">
                       <span className="text-indigo-200 text-5xl font-black italic">#{idx + 1}</span>
                       {q.question}
                    </p>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {q.options.map((opt) => (
                        <button
                          key={opt}
                          onClick={() => setAnswers({...answers, [idx]: opt})}
                          className={`p-6 rounded-2xl border-2 text-left text-xl transition-all ${
                            answers[idx] === opt 
                              ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-[1.03]' 
                              : 'bg-slate-50 border-slate-100 text-slate-600 hover:border-indigo-200'
                          }`}
                        >
                          <span className="font-bold">{opt}</span>
                        </button>
                      ))}
                    </div>
                  </div>
                ))}
                <button 
                  onClick={handleQuizSubmit}
                  disabled={Object.keys(answers).length < quiz.length}
                  className="w-full bg-indigo-600 text-white font-black py-6 rounded-3xl text-2xl disabled:bg-slate-200 disabled:text-slate-400 hover:bg-indigo-700 shadow-xl transition-all"
                >
                  Verify Results
                </button>
              </div>
            )}

            {step === 'result' && (
              <div className="text-center py-12 animate-in zoom-in duration-500">
                <div className="text-[120px] mb-8 animate-bounce">
                  {quizScore >= 4 ? '🏅' : '🧗'}
                </div>
                <h3 className="text-6xl font-display font-black mb-4">
                  {quizScore === quiz.length ? 'Perfekt!' : 'Gut gemacht!'}
                </h3>
                <p className="text-3xl text-slate-400 mb-12">
                   Scored <span className="text-indigo-600 font-black">{quizScore} / {quiz.length}</span> in {lesson.topic}
                </p>

                <div className="bg-white p-10 rounded-[40px] shadow-xl border border-indigo-50 max-w-2xl mx-auto mb-12">
                   <p className="font-marker text-indigo-600 text-2xl mb-4">Lernfortschritt:</p>
                   <p className="text-lg text-slate-600 leading-relaxed">
                     You've successfully added these concepts to your German mental library. Every lesson brings you closer to A2 fluency!
                   </p>
                </div>

                <button 
                  onClick={onComplete}
                  className="w-full max-w-md bg-slate-900 text-white font-black py-6 rounded-3xl text-2xl hover:bg-black shadow-2xl transition-all"
                >
                  Back to Dashboard
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

