import React, { useState, useEffect } from 'react';
import { ProficiencyLevel, Lesson, UserProgress } from './types';
import { INITIAL_LESSONS, NAV_ITEMS } from './constants';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import LessonsView from './components/LessonsView';
import PracticeView from './components/PracticeView';
import ExamsView from './components/ExamsView';
import LessonModal from './components/LessonModal';
import ContributionView from './components/ContributionView';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [userProgress, setUserProgress] = useState<UserProgress>({
    completedLessons: [],
    examScores: {},
    totalProgress: 0,
    level: ProficiencyLevel.A1
  });
  const [lessons, setLessons] = useState<Lesson[]>(INITIAL_LESSONS);
  const [selectedLesson, setSelectedLesson] = useState<Lesson | null>(null);

  // Calculate progress whenever completedLessons changes
  useEffect(() => {
    const total = lessons.length;
    const completedCount = userProgress.completedLessons.length;
    const percentage = Math.round((completedCount / total) * 100);
    setUserProgress(prev => ({ ...prev, totalProgress: percentage }));
  }, [userProgress.completedLessons, lessons.length]);

  const handleCompleteLesson = (lessonId: string) => {
    if (!userProgress.completedLessons.includes(lessonId)) {
      const nextCompleted = [...userProgress.completedLessons, lessonId];
      setUserProgress(prev => ({ ...prev, completedLessons: nextCompleted }));

      // Unlock next lesson logic
      setLessons(prev => {
        const index = prev.findIndex(l => l.id === lessonId);
        const updated = [...prev];
        updated[index] = { ...updated[index], status: 'completed', progress: 100 };
        if (updated[index + 1]) {
          updated[index + 1] = { ...updated[index + 1], status: 'available' };
        }
        return updated;
      });
    }
    setSelectedLesson(null);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard progress={userProgress} lessons={lessons} />;
      case 'lessons':
        return <LessonsView lessons={lessons} onSelectLesson={setSelectedLesson} />;
      case 'practice':
        return <PracticeView level={userProgress.level} />;
      case 'exams':
        return <ExamsView level={userProgress.level} onCompleteExam={(score) => console.log('Exam Score:', score)} />;
      case 'contribution':
        return <ContributionView />;
      case 'achievements':
        return (
          <div className="p-8 text-center">
            <h1 className="text-3xl font-bold mb-4">Your Achievements</h1>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {['Early Bird', 'Vocab Master', 'Perfect Score', 'German Native'].map(a => (
                <div key={a} className="p-6 bg-white rounded-xl shadow-sm border border-gray-100 flex flex-col items-center">
                   <span className="text-4xl mb-2">🏅</span>
                   <span className="font-semibold">{a}</span>
                </div>
              ))}
            </div>
          </div>
        );
      default:
        return <Dashboard progress={userProgress} lessons={lessons} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 overflow-y-auto">
        <header className="bg-white border-b border-gray-200 px-8 py-4 flex justify-between items-center sticky top-0 z-10">
          <div>
            <h2 className="text-xl font-bold text-slate-800">Guten Tag! 👋</h2>
            <p className="text-sm text-slate-500">Welcome back to your German journey.</p>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <div className="text-sm font-medium">Level: <span className="text-indigo-600 font-bold">{userProgress.level}</span></div>
              <div className="text-xs text-slate-400">Next goal: {userProgress.level === 'A1' ? 'A2' : 'B1'}</div>
            </div>
            <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold border-2 border-indigo-200">
              DU
            </div>
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>

      {selectedLesson && (
        <LessonModal 
          lesson={selectedLesson} 
          onClose={() => setSelectedLesson(null)} 
          onComplete={() => handleCompleteLesson(selectedLesson.id)} 
        />
      )}
    </div>
  );
};

export default App;

