    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 p-4 md:p-12 overflow-y-auto">
      <div className="bg-[#f8f9fc] rounded-[40px] shadow-3xl w-full max-w-7xl max-h-full overflow-hidden relative flex flex-col md:flex-row border-8 border-white">

